#include <stdio.h>
#include <string.h>

struct Student {
    char name[50];
    int rollNo;
    float marks;
};

int main() {
    int n;
    printf("Enter number of students: ");
    scanf("%d", &n);

    struct Student class[n]; // VLA in C99

    // Input student details
    for (int i = 0; i < n; i++) {
        printf("\nEnter details for student %d:\n", i+1);
        printf("Name: ");
        scanf("%s", class[i].name);
        printf("Roll No: ");
        scanf("%d", &class[i].rollNo);
        printf("Marks: ");
        scanf("%f", &class[i].marks);
    }

    // Display all students
    printf("\nStudent Records:\n");
    printf("%-20s %-10s %-10s\n", "Name", "Roll No", "Marks");
    for (int i = 0; i < n; i++) {
        printf("%-20s %-10d %-10.2f\n", 
               class[i].name, class[i].rollNo, class[i].marks);
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int *arr;
    int size = 5;
    int newSize;

    // Allocate memory for 5 integers
    arr = (int*)malloc(size * sizeof(int));

    if (arr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Initialize array with values
    printf("Initial array of size %d:\n", size);
    for (int i = 0; i < size; i++) {
        arr[i] = (i + 1) * 10;
        printf("arr[%d] = %d\n", i, arr[i]);
    }

    // Ask user to resize
    printf("\nEnter new size: ");
    scanf("%d", &newSize);

    // Resize the array
    arr = (int*)realloc(arr, newSize * sizeof(int));

    if (arr == NULL) {
        printf("Memory reallocation failed!\n");
        return 1;
    }

    printf("\nResized array of size %d:\n", newSize);
    for (int i = 0; i < newSize; i++) {
        if (i < size) {
            printf("arr[%d] = %d (old)\n", i, arr[i]);
        } else {
            arr[i] = (i + 1) * 10;
            printf("arr[%d] = %d (new)\n", i, arr[i]);
        }
    }

    // Free the allocated memory
    free(arr);
    printf("\nMemory freed successfully.\n");

    return 0;
}

#include <stdio.h>

#define ROWS 3
#define COLS 3

int main() {
    // Declare two 3x3 matrices
    int A[ROWS][COLS] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };

    int B[ROWS][COLS] = {
        {9, 8, 7},
        {6, 5, 4},
        {3, 2, 1}
    };

    int C[ROWS][COLS]; // Result matrix

    // Matrix Addition: C = A + B
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            C[i][j] = A[i][j] + B[i][j];
        }
    }

    // Display result
    printf("Matrix A + Matrix B = Matrix C\n\n");

    for (int i = 0; i < ROWS; i++) {
        // Print row of A
        printf("[");
        for (int j = 0; j < COLS; j++) {
            printf("%3d ", A[i][j]);
        }
        printf("]");

        // Print operator
        if (i == 1) printf("   +   ");
        else printf("       ");

        // Print row of B
        printf("[");
        for (int j = 0; j < COLS; j++) {
            printf("%3d ", B[i][j]);
        }
        printf("]");

        // Print result
        if (i == 1) printf("   =   ");
        else printf("       ");

        printf("[");
        for (int j = 0; j < COLS; j++) {
            printf("%3d ", C[i][j]);
        }
        printf("]\n");
    }

    return 0;
}
